const promptId = $input.item.json.prompt_id;

// 🌟 核心精简：直接去拿“概览生成”那个节点输出的纯净 JSON，彻底抛弃中间的 ComfyUI 工作流参数
const cleanCourseOverview = $('构建图片工作流').first().json.courseOverview;

const comfyUrl = "https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com";
const maxAttempts = 600;

for (let i = 0; i < maxAttempts; i++) {
  // 每 3 秒查一次
  await new Promise(r => setTimeout(r, 3000));

  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `${comfyUrl}/history/${promptId}`,
      json: true
    });

    const taskData = Object.values(res)[0];

    if (taskData && taskData.outputs) {
      const images = taskData.outputs['10']?.images || [];
      if (images.length > 0) {
        const img = images[0];
        const imageUrl = `${comfyUrl}/view?filename=${img.filename}&subfolder=${img.subfolder || ''}&type=${img.type || 'output'}`;

        // 🎉 这里是最后输出给 Webhook 的结果：只有概览文本和图片地址，极其干净！
        return {
          courseOverview: cleanCourseOverview,
          themeImageUrl: imageUrl
        };
      }
    }

    if (taskData?.status?.status_str === 'error') {
      return {
        courseOverview: cleanCourseOverview,
        themeImageUrl: null,
        error: '图片生成失败(ComfyUI内部报错)'
      };
    }
  } catch (e) {
    console.log("轮询报错，继续重试:", e.message);
  }
}

// 超时情况的返回
return {
  courseOverview: cleanCourseOverview,
  themeImageUrl: null,
  error: '图片生成超时'
};

// 1. 获取前置节点的数据，并做兼容处理（防止大模型输出包裹在 text 字段中）
const raw = $input.item.json;
let overview = raw.courseOverview;

if (!overview && raw.text) {
  try {
    overview = JSON.parse(raw.text).courseOverview;
  } catch(e) {}
}
if (!overview) {
  overview = raw; // 兜底逻辑
}

// 2. 生成随机种子，确保每次调用的画面都不一样
const seed = Math.floor(Math.random() * 1000000000000);

// 3. 动态提示词（可替换为你从上游取到的动态变量）
const imagePrompt = "扁平矢量插画，粗细均匀的黑色轮廓线，单线风格，2D扁平设计，无渐变，无阴影，低饱和度的平涂色彩、和谐的柔和色调、连贯的配色方案，简化但风格化的背景环境，清晰的环境线稿，非写实扁平插画，角色的符号化表情，干净亲和的美学，沉浸式叙事扁平背景，画面无人物无文字, flat vector illustration, uniform thick black outlines, beautiful lush green magical forest, tall trees, sunlight filtering through leaves, wild nature, empty scene, absolutely no people.";

// 4. 构建 ComfyUI 工作流
const workflow = {
  "1": {
    "inputs": {
      "unet_name": "z_image_turbo_bf16.safetensors",
      "weight_dtype": "default"
    },
    "class_type": "UNETLoader",
    "_meta": { "title": "UNet加载器" }
  },
  "2": {
    "inputs": { "vae_name": "ae.safetensors" },
    "class_type": "VAELoader",
    "_meta": { "title": "加载VAE" }
  },
  "3": {
    "inputs": {
      "clip_name": "qwen_3_4b.safetensors",
      "type": "lumina2",
      "device": "default"
    },
    "class_type": "CLIPLoader",
    "_meta": { "title": "加载CLIP" }
  },
  "4": {
    "inputs": {
      "shift": 3,
      "model": [ "1", 0 ]
    },
    "class_type": "ModelSamplingAuraFlow",
    "_meta": { "title": "采样算法（AuraFlow）" }
  },
  "5": {
    "inputs": {
      "width": 2048,
      "height": 1152,
      "batch_size": 1
    },
    "class_type": "EmptySD3LatentImage",
    "_meta": { "title": "空Latent图像（SD3）" }
  },
  "6": {
    "inputs": {
      "text": imagePrompt,
      "clip": [ "3", 0 ]
    },
    "class_type": "CLIPTextEncode",
    "_meta": { "title": "1. 万能场景正向提示词" }
  },
  "7": {
    "inputs": {
      "text": "people, humans, characters, animals, blurry, realistic, 3d, complex gradients, dark shadows.human, realistic, detailed face",
      "clip": [ "3", 0 ]
    },
    "class_type": "CLIPTextEncode",
    "_meta": { "title": "2. 背景负面提示词" }
  },
  "8": {
    "inputs": {
      "seed": seed,
      "steps": 15,
      "cfg": 1.5,
      "sampler_name": "euler",
      "scheduler": "simple",
      "denoise": 1,
      "model": [ "4", 0 ],
      "positive": [ "6", 0 ],
      "negative": [ "7", 0 ],
      "latent_image": [ "5", 0 ]
    },
    "class_type": "KSampler",
    "_meta": { "title": "3. 生成场景" }
  },
  "9": {
    "inputs": {
      "samples": [ "8", 0 ],
      "vae": [ "2", 0 ]
    },
    "class_type": "VAEDecode",
    "_meta": { "title": "背景解码" }
  },
  "10": {
    "inputs": {
      "filename_prefix": "Universal_Scene",
      "images": [ "9", 0 ]
    },
    "class_type": "SaveImage",
    "_meta": { "title": "保存纯净背景" }
  }
};

// 5. 返回组装好的对象，将大模型生成的概览数据一起透传下去
return {
  courseOverview: overview, 
  comfyuiPayload: { 
    prompt: workflow 
  }
};
